data.usage#Usage:
Blocks compose core components with sensible defaults:
import { PageBuilder, MetricStripBlock } from '@mfe/blocks';
import { EntityGridTemplate, DataGridFilterChips } from '@mfe/x-data-grid';
function InvoicesPage() {
  return (
    <PageBuilder
      title="Invoices"
      stats={<MetricStripBlock items={kpis} />}
      filters={<DataGridFilterChips filters={filterConfig} />}
    >
      <EntityGridTemplate rows={invoices} columns={columns} />
    </PageBuilder>
  );
}

data.customization#Customization:
Override block defaults via props or wrap with custom styles:
<PageHeader
  title="Dashboard"
  breadcrumbs={[{ label: 'Home', href: '/' }, { label: 'Dashboard' }]}
  actions={<Button>Export</Button>}
/>

data.override-block-props#Override Block Prop:
Every block accepts a props object that maps to its internal components. Pass
overrides to change behavior without forking the block:
import { DataListBlock } from '@mfe/blocks';
export function InvoicePage() {
  return (
    <DataListBlock
      title="Recent Invoices"
      pageSize={25}
      columns={['number', 'customer', 'amount', 'status', 'date']}
      onRowClick={(invoice) => router.push(`/invoices/${invoice.id}`)}
      emptyState={<EmptyInvoices />}
    />
  );
}
Props are merged with the block's defaults. Any prop you do not provide falls
back to the built-in default value.

data.custom-theme-integration#Custom Theme In:
Blocks inherit the active theme from the design-system ThemeProvider. To apply
a custom theme:
import { ThemeProvider, setAppearance } from '@mfe/design-system';
import { KPIDashboardBlock } from '@mfe/blocks';
// Configure appearance via the design-system API
setAppearance({
  palette: {
    primary: { main: '#1a56db' },
    background: { default: '#f8fafc' },
  },
  shape: { borderRadius: 12 },
});
export function Dashboard() {
  return (
    <ThemeProvider>
      <KPIDashboardBlock />
    </ThemeProvider>
  );
}
Blocks use design tokens internally, so they automatically adapt to your custom
palette, typography, spacing, and shape values.

data.token-override-granularity#Token Overrid:
For fine-grained control, override specific tokens in the theme:
// Use setAppearance to override component tokens
setAppearance({
  components: {
    MfeBlockCard: {
      styleOverrides: {
        root: {
          boxShadow: 'none',
          border: '1px solid var(--color-border-subtle)',
        },
      },
    },
  },
});

data.slot-based-composition#Slot-Based Compos:
Blocks expose named slots for replacing internal sections without overriding
the entire block:
import { DetailViewBlock } from '@mfe/blocks';
export function CustomerPage() {
  return (
    <DetailViewBlock
      slots={{
        header: <CustomHeader />,
        sidebar: <CustomSidebar />,
        footer: null, // remove the footer entirely
      }}
      slotProps={{
        header: { showBreadcrumb: true },
        sidebar: { collapsible: true },
      }}
    />
  );
}

data.slot-props-forwarding#Slot Props Forward:
Use slotProps to pass props to slot components without wrapping them manually:
<OrderListBlock
  slots={{ toolbar: <AdvancedToolbar /> }}
  slotProps={{
    toolbar: {
      showExport: true,
      showColumnToggle: true,
      exportFormats: ['csv', 'xlsx'],
    },
  }}
/>

data.first-component#First Component:
Wrap your application with ThemeProvider and start using components:
import { ThemeProvider, Button, Input } from '@mfe/design-system';
function App() {
  return (
    <ThemeProvider>
      <Input placeholder="Email" />
      <Button variant="contained">Submit</Button>
    </ThemeProvider>
  );
}

data.theming#Theming:
Customize the theme by passing defaultAxes to ThemeProvider:
import { ThemeProvider } from '@mfe/design-system';
import type { ThemeAxes } from '@mfe/design-system';
const axes: Partial<ThemeAxes> = {
  appearance: 'light',
  density: 'comfortable',
  radius: 'md',
};
function App() {
  return (
    <ThemeProvider defaultAxes={axes}>
      {/* Your app */}
    </ThemeProvider>
  );
}

